/*
 * GPU Vector Addition - CUDA C Implementation
 * Demonstrates basic GPGPU programming workflow
 */

#include <stdio.h>
#include <stdlib.h>
#include <cuda_runtime.h>

// Error checking macro
#define CUDA_CHECK(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 fprintf(stderr, "CUDA error at %s:%d: %s\n", \
 __FILE__, __LINE__, cudaGetErrorString(err)); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

// CUDA Kernel: Each thread performs one element addition
__global__ void vectorAdd(float *A, float *B, float *C, int n) {
 // Calculate global thread index
 int i = blockIdx.x * blockDim.x + threadIdx.x;

 // Boundary check: ensure thread is within vector bounds
 if (i < n) {
 C[i] = A[i] + B[i];
 }
}

int main(int argc, char *argv[]) {
 // Vector size (default: 1M elements)
 int n = 1024 * 1024;
 size_t bytes = n * sizeof(float);

 printf("=== CUDA Vector Addition ===\n");
 printf("Vector size: %d elements (%.2f MB)\n", n, bytes / (1024.0 * 1024.0));

 // Allocate host memory (CPU)
 float *h_A = (float*)malloc(bytes);
 float *h_B = (float*)malloc(bytes);
 float *h_C = (float*)malloc(bytes);

 // Initialize input vectors with random values
 for (int i = 0; i < n; i++) {
 h_A[i] = (float)rand() / RAND_MAX;
 h_B[i] = (float)rand() / RAND_MAX;
 }

 // Declare device pointers (GPU memory)
 float *d_A, *d_B, *d_C;

 // Allocate device memory (GPU)
 CUDA_CHECK(cudaMalloc((void**)&d_A, bytes));
 CUDA_CHECK(cudaMalloc((void**)&d_B, bytes));
 CUDA_CHECK(cudaMalloc((void**)&d_C, bytes));

 // Copy input data from Host to Device (H2D)
 CUDA_CHECK(cudaMemcpy(d_A, h_A, bytes, cudaMemcpyHostToDevice));
 CUDA_CHECK(cudaMemcpy(d_B, h_B, bytes, cudaMemcpyHostToDevice));

 // Configure kernel launch parameters
 int threadsPerBlock = 256;
 int blocksPerGrid = (n + threadsPerBlock - 1) / threadsPerBlock;

 printf("Launching kernel: %d blocks, %d threads/block\n", 
 blocksPerGrid, threadsPerBlock);

 // Launch the GPU kernel
 vectorAdd<<<blocksPerGrid, threadsPerBlock>>>(d_A, d_B, d_C, n);

 // Check for kernel launch errors
 CUDA_CHECK(cudaGetLastError());

 // Synchronize: wait for kernel to complete
 CUDA_CHECK(cudaDeviceSynchronize());

 // Copy result from Device to Host (D2H)
 CUDA_CHECK(cudaMemcpy(h_C, d_C, bytes, cudaMemcpyDeviceToHost));

 // Verify results (sample check)
 int errors = 0;
 for (int i = 0; i < n && errors < 5; i++) {
 float expected = h_A[i] + h_B[i];
 if (fabsf(h_C[i] - expected) > 1e-5) {
 errors++;
 if (errors == 1) {
 printf("Error at index %d: got %f, expected %f\n", 
 i, h_C[i], expected);
 }
 }
 }

 if (errors == 0) {
 printf("SUCCESS: All values verified!\n");
 } else {
 printf("FAILED: %d errors found\n", errors);
 }

 // Free device memory
 CUDA_CHECK(cudaFree(d_A));
 CUDA_CHECK(cudaFree(d_B));
 CUDA_CHECK(cudaFree(d_C));

 // Free host memory
 free(h_A);
 free(h_B);
 free(h_C);

 // Reset device (best practice)
 CUDA_CHECK(cudaDeviceReset());

 printf("=== Execution Complete ===\n");
 return 0;
}

ALGORITHM GPU_SIMT_Execution_Model
INPUT: Grid of thread blocks, each containing multiple threads
OUTPUT: Execution of all threads in parallel following SIMT model

BEGIN
 // GPU Architecture Overview
 // =========================
 // GPU contains multiple Streaming Multiprocessors (SMs)
 // Each SM contains many processing cores
 // Threads are grouped into warps (32 threads each)

 // Thread Organization
 // ===================
 // Grid: Contains multiple thread blocks
 // Block: Contains multiple threads (max 1024 per block)
 // Warp: 32 threads executing in lockstep (fundamental scheduling unit)

 // Warp Execution Process
 // =======================
 FOR each thread_block IN grid DO
 // Divide block threads into warps
 warps_in_block = CEILING(block_thread_count / 32)

 FOR each warp_index FROM 0 TO warps_in_block - 1 DO
 // All 32 threads in warp execute same instruction
 // This is the SIMT (Single Instruction, Multiple Threads) model

 IF warp_is_ready THEN
 // Select one warp to execute on SM
 selected_warp = SELECT_WARP_FROM_READY_QUEUE()

 // All threads in warp execute SAME instruction simultaneously
 EXECUTE_INSTRUCTION(selected_warp)

 // If threads branch differently (if-else), 
 // warp executes both paths (serialized)
 // This is called "warp divergence"
 END IF
 END FOR
 END FOR

 // Memory Access Coalescing
 // =========================
 // Consecutive threads should access consecutive memory addresses
 // This allows the GPU to fetch data in a single transaction

 // Example: COALESCED (good)
 // Thread 0 accesses address 100
 // Thread 1 accesses address 104
 // Thread 2 accesses address 108
 // ... all in one memory transaction

 // Example: NON-COALESCED (bad)
 // Thread 0 accesses address 100
 // Thread 1 accesses address 200 // Not consecutive!
 // Thread 2 accesses address 300 // Not consecutive!
 // ... requires multiple memory transactions
END

ALGORITHM Calculate_Global_Thread_ID
INPUT: blockIdx (block index), blockDim (threads per block), threadIdx (thread index)
OUTPUT: Unique global thread ID

BEGIN
 // Linearize 3D/2D thread indices to 1D global ID
 // Formula: global_id = blockIdx.x * blockDim.x + threadIdx.x

 global_id_x = blockIdx.x * blockDim.x + threadIdx.x
 global_id_y = blockIdx.y * blockDim.y + threadIdx.y
 global_id_z = blockIdx.z * blockDim.z + threadIdx.z

 // For 2D grid: global_id = global_id_y * (gridDim.x * blockDim.x) + global_id_x
 // For 1D grid: global_id = global_id_x

 RETURN global_id_x // For 1D case
END
